class Controller{constructor(){this.model=new Model({onMemesChange:this.handleModelMemesChange,onCurrentMemeIdChange:this.handleModelCurrentMemeIdChange,onTextTopChange:this.handleModelTextTopChange,onTextBottomChange:this.handleModelTextBottomChange}),this.view=new View({onMemeChange:this.handleViewMemeChange,onTextTopChange:this.handleViewTextTopChange,onTextBottomChange:this.handleViewTextBottomChange}),this.api=new API}init(){this.api.getMemes().then(e=>{let t=e.data.memes;this.model.setMemes(t)})}handleModelMemesChange=()=>{this.view.renderMemesSelect(this.model.getMemes(),this.model.getCurrentMemeId())};handleModelCurrentMemeIdChange=()=>{this.view.renderPreview(this.model.getPreview())};handleModelTextTopChange=()=>{this.view.renderPreview(this.model.getPreview())};handleModelTextBottomChange=()=>{this.view.renderPreview(this.model.getPreview())};handleViewMemeChange=e=>{this.model.setCurrentMemeId(e)};handleViewTextTopChange=e=>{e.length<=10&&this.model.setTextTop(e)};handleViewTextBottomChange=e=>{e.length<=10&&this.model.setTextBottom(e)}}